import { useState, useEffect, useCallback } from 'react';
import { Flame, TrendingUp, Trophy, Calendar, Users, Sparkles, Plus, Check, ClipboardList } from 'lucide-react';
import { Link } from 'react-router-dom';
import api from '../../config/api';

// ─── Helpers ───────────────────────────────────────────────────────────────

function formatCountdown(dateStr) {
  const diff = new Date(dateStr) - new Date();
  if (diff <= 0) return 'Ongoing';
  const d = Math.floor(diff / 86400000);
  const h = Math.floor((diff % 86400000) / 3600000);
  const m = Math.floor((diff % 3600000) / 60000);
  if (d > 0) return `${d}d ${h}h`;
  if (h > 0) return `${h}h ${m}m`;
  return `${m}m`;
}

function timeAgo(dateStr) {
  const diff = Date.now() - new Date(dateStr);
  const m = Math.floor(diff / 60000);
  if (m < 1) return 'just now';
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  return `${Math.floor(h / 24)}d ago`;
}

const CATEGORY_COLORS = {
  hackathon: 'text-orange-400 bg-orange-400/10',
  workshop: 'text-blue-400 bg-blue-400/10',
  seminar: 'text-purple-400 bg-purple-400/10',
  cultural: 'text-pink-400 bg-pink-400/10',
  sports: 'text-green-400 bg-green-400/10',
  club: 'text-yellow-400 bg-yellow-400/10',
  meetup: 'text-cyan-400 bg-cyan-400/10',
  other: 'text-dark-400 bg-dark-400/10',
};

function CategoryBadge({ category }) {
  const cls = CATEGORY_COLORS[category] || CATEGORY_COLORS.other;
  return (
    <span className={`text-[10px] font-semibold px-2 py-0.5 rounded-full capitalize ${cls}`}>
      {category}
    </span>
  );
}

// ─── Stat Row ───────────────────────────────────────────────────────────────
function StatRow({ label, value }) {
  return (
    <div className="flex items-center justify-between py-1.5">
      <span className="text-xs text-dark-400">{label}</span>
      <span className="text-xs font-semibold text-dark-100">{value}</span>
    </div>
  );
}

// ─── Skeleton ───────────────────────────────────────────────────────────────
function SkeletonBlock({ h = 'h-4', w = 'w-full', mb = '' }) {
  return <div className={`${h} ${w} ${mb} bg-dark-800/60 rounded animate-pulse`} />;
}

// ─── Main Component ─────────────────────────────────────────────────────────

export default function EventSidebar() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [countdown, setCountdown] = useState({});

  const fetchData = useCallback(async () => {
    try {
      const res = await api.get('/events/sidebar-data');
      setData(res.data.data);
    } catch (err) {
      console.error('[EventSidebar] Failed to load sidebar data', err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleRSVP = async (e, eventId, status) => {
    e.preventDefault();
    try {
      await api.post(`/events/${eventId}/rsvp`, { status });
      fetchData(); // Refresh sidebar data immediately to show updated stats/lists
    } catch (err) {
      console.error('[EventSidebar] RSVP failed', err);
    }
  };

  // Countdown tick — every 60s, only update state if component still mounted
  useEffect(() => {
    if (!data?.upcoming?.length) return;
    const tick = () => {
      const next = {};
      data.upcoming.forEach(({ event }) => {
        if (event?._id) next[event._id] = formatCountdown(event.startDate);
      });
      setCountdown(next);
    };
    tick();
    const id = setInterval(tick, 60000);
    return () => clearInterval(id);
  }, [data]);

  const engagementBadgeColor = {
    Newcomer: 'text-dark-400',
    Explorer: 'text-blue-400',
    'Rising Star': 'text-yellow-400',
    'Active Participant': 'text-primary-400',
    'Campus Leader': 'text-orange-400',
  };

  return (
    <aside className="w-80 fixed right-0 top-0 bottom-0 bg-dark-950 border-l border-dark-800 hidden xl:block overflow-y-auto overflow-x-hidden hide-scrollbar">
      <div className="p-6">
        {/* ── 1. Your Event Stats ── */}
      <div className="bg-dark-900/50 rounded-2xl p-5 border border-dark-800 mb-6">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-yellow-400/20 to-yellow-600/10 border border-yellow-500/20 flex items-center justify-center shadow-[0_0_15px_rgba(250,204,21,0.1)]">
            <Trophy size={14} className="text-yellow-400" />
          </div>
          <h3 className="text-sm font-semibold text-dark-200">Your Event Stats</h3>
        </div>
        {loading ? (
          <div className="space-y-2">
            {[...Array(4)].map((_, i) => <SkeletonBlock key={i} h="h-4" />)}
          </div>
        ) : (
          <div className="divide-y divide-dark-800/60">
            <StatRow label="Events Joined" value={data?.stats?.eventsJoined ?? 0} />
            <StatRow label="Workshops Attended" value={data?.stats?.workshopsAttended ?? 0} />
            <StatRow label="Hackathons" value={data?.stats?.hackathonsParticipated ?? 0} />
            <StatRow label="Certificates" value={data?.stats?.certificatesEarned ?? 0} />
          </div>
        )}
        {!loading && (
          <div className="mt-3 pt-2 border-t border-dark-800/60 flex items-center gap-2">
            <span className="text-[10px] text-dark-500">Engagement Level</span>
            <span className={`text-[11px] font-bold ${engagementBadgeColor[data?.stats?.engagementLevel] || 'text-dark-400'}`}>
              {data?.stats?.engagementLevel || 'Newcomer'}
            </span>
          </div>
        )}
      </div>

      {/* ── 2. Upcoming Events ── */}
      <div className="bg-dark-900/50 rounded-2xl p-5 border border-dark-800 mb-6">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-primary-400/20 to-primary-600/10 border border-primary-500/20 flex items-center justify-center shadow-[0_0_15px_rgba(92,124,250,0.1)]">
              <Calendar size={14} className="text-primary-400" />
            </div>
            <h3 className="text-sm font-semibold text-dark-200">Upcoming Events</h3>
          </div>
          <Link to="/events" className="text-[10px] text-primary-400 hover:text-primary-300 transition-colors">
            View all
          </Link>
        </div>
        {loading ? (
          <div className="space-y-3">
            {[...Array(2)].map((_, i) => (
              <div key={i} className="space-y-1.5">
                <SkeletonBlock h="h-3.5" w="w-3/4" />
                <SkeletonBlock h="h-3" w="w-1/2" />
              </div>
            ))}
          </div>
        ) : !data?.upcoming?.length ? (
          <p className="text-xs text-dark-500 py-2">No registered upcoming events.</p>
        ) : (
          <div className="space-y-4">
            {data.upcoming.map(({ event, status }) => (
              <Link key={event._id} to={`/events/${event._id}`} className="flex gap-3 group cursor-pointer block">
                <div className="w-10 h-10 rounded-xl bg-dark-800 flex flex-col items-center justify-center border border-dark-700/50 group-hover:border-primary-500/30 transition-colors">
                  <span className="text-[10px] text-dark-400 font-medium uppercase">{countdown[event._id] || formatCountdown(event.startDate)}</span>
                </div>
                <div className="flex-1 min-w-0">
                  <h4 className="text-sm font-medium text-dark-200 group-hover:text-primary-300 transition-colors truncate">{event.title}</h4>
                  <div className="flex items-center justify-between mt-1">
                    <div className="flex items-center gap-1.5">
                      <CategoryBadge category={event.category} />
                    </div>
                    <span className="text-[10px] text-dark-500 capitalize">{status}</span>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        )}
      </div>

      {/* ── 3. Recommended For You ── */}
      <div className="bg-dark-900/50 rounded-2xl p-5 border border-dark-800 mb-6">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-purple-400/20 to-purple-600/10 border border-purple-500/20 flex items-center justify-center shadow-[0_0_15px_rgba(168,85,247,0.1)]">
            <Sparkles size={14} className="text-purple-400" />
          </div>
          <h3 className="text-sm font-semibold text-dark-200">Recommended For You</h3>
        </div>
        {loading ? (
          <div className="space-y-3">
            {[...Array(2)].map((_, i) => (
              <div key={i} className="space-y-1.5">
                <SkeletonBlock h="h-10" w="w-full" />
              </div>
            ))}
          </div>
        ) : !data?.recommended?.length ? (
          <p className="text-xs text-dark-500 py-2">Keep exploring events for recommendations!</p>
        ) : (
          <div className="space-y-4">
            {data.recommended.map((event) => (
              <Link key={event._id} to={`/events/${event._id}`} className="block group bg-dark-800/40 rounded-xl p-3 border border-dark-700/50 hover:border-primary-500/30 transition-colors">
                <div className="flex gap-3">
                  <div className="w-12 h-12 rounded-lg overflow-hidden flex-shrink-0 bg-dark-800">
                    <img src={event.bannerUrl || 'https://via.placeholder.com/150'} alt={event.title} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <h4 className="text-sm font-medium text-dark-200 group-hover:text-primary-300 transition-colors truncate">{event.title}</h4>
                    <p className="text-[10px] text-dark-500 truncate mb-2">{event.reason}</p>
                    <div className="flex items-center gap-2">
                      <button onClick={(e) => handleRSVP(e, event._id, 'registered')} className="flex-1 py-1.5 bg-primary-600 hover:bg-primary-500 text-white text-[10px] font-semibold rounded-md transition-colors flex items-center justify-center gap-1">
                        <Check size={12} /> RSVP
                      </button>
                      <button onClick={(e) => handleRSVP(e, event._id, 'interested')} className="flex-1 py-1.5 bg-dark-700 hover:bg-dark-600 text-dark-200 text-[10px] font-semibold rounded-md transition-colors flex items-center justify-center gap-1">
                        <Plus size={12} /> Interested
                      </button>
                    </div>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        )}
      </div>

      {/* ── 4. Trending This Week ── */}
      <div className="bg-dark-900/50 rounded-2xl p-5 border border-dark-800 mb-6">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-orange-400/20 to-orange-600/10 border border-orange-500/20 flex items-center justify-center shadow-[0_0_15px_rgba(249,115,22,0.1)]">
            <TrendingUp size={14} className="text-orange-400" />
          </div>
          <h3 className="text-sm font-semibold text-dark-200">Trending This Week</h3>
        </div>
        {loading ? (
          <div className="space-y-3">
            {[...Array(3)].map((_, i) => (
              <div key={i} className="space-y-1.5">
                <SkeletonBlock h="h-3.5" w="w-3/4" />
                <SkeletonBlock h="h-3" w="w-2/5" />
              </div>
            ))}
          </div>
        ) : !data?.trending?.length ? (
          <p className="text-xs text-dark-500 py-2">No trending events yet.</p>
        ) : (
          <div className="space-y-4">
            {data.trending.map((item, idx) => (
              <Link key={item.eventId} to={`/events/${item.eventId}`} className="flex gap-3 group cursor-pointer block">
                <div className={`w-10 h-10 rounded-xl bg-dark-800 flex flex-col items-center justify-center border border-dark-700/50 group-hover:border-primary-500/30 transition-colors ${idx === 0 ? 'text-orange-400' : idx === 1 ? 'text-dark-400' : 'text-dark-500'}`}>
                  <span className="text-sm font-bold">#{idx + 1}</span>
                </div>
                <div className="flex-1 min-w-0">
                  <h4 className="text-sm font-medium text-dark-200 group-hover:text-primary-300 transition-colors truncate">{item.title}</h4>
                  <div className="flex items-center justify-between mt-1">
                    <span className="text-[10px] text-dark-500">+{item.weeklyCount} this week</span>
                    {idx === 0 && <Flame size={12} className="text-orange-400" />}
                  </div>
                </div>
              </Link>
            ))}
          </div>
        )}
      </div>

      {/* ── 5. Your Registrations ── */}
      <div className="bg-dark-900/50 rounded-2xl p-5 border border-dark-800 mb-6">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-green-400/20 to-green-600/10 border border-green-500/20 flex items-center justify-center shadow-[0_0_15px_rgba(34,197,94,0.1)]">
            <ClipboardList size={14} className="text-green-400" />
          </div>
          <h3 className="text-sm font-semibold text-dark-200">Your Registrations</h3>
        </div>
        {loading ? (
          <div className="space-y-2.5">
            {[...Array(4)].map((_, i) => <SkeletonBlock key={i} h="h-3.5" />)}
          </div>
        ) : !data?.yourRegistrations ? (
          <p className="text-xs text-dark-500 py-2">No registrations found.</p>
        ) : (
          <div>
            <div className="divide-y divide-dark-800/60 mb-4">
              <StatRow label="Total Registered" value={data.yourRegistrations.total} />
              <StatRow label="Upcoming This Week" value={data.yourRegistrations.upcomingThisWeek} />
              <StatRow label="Completed Events" value={data.yourRegistrations.completed} />
              <StatRow label="Pending Approvals" value={data.yourRegistrations.pending} />
            </div>

            {data.yourRegistrations.latestEvent && (
              <div>
                <h4 className="text-[10px] text-dark-500 uppercase tracking-wider font-semibold mb-2">Latest Registration</h4>
                <Link to={`/events/${data.yourRegistrations.latestEvent._id}`} className="block group bg-dark-800/40 rounded-xl p-3 border border-dark-700/50 hover:border-primary-500/30 transition-colors">
                  <div className="flex gap-3">
                    <div className="flex-1 min-w-0">
                      <h4 className="text-sm font-medium text-dark-200 group-hover:text-primary-300 transition-colors truncate">{data.yourRegistrations.latestEvent.title}</h4>
                      <div className="flex items-center justify-between mt-2">
                        <div className="flex items-center gap-2">
                          <CategoryBadge category={data.yourRegistrations.latestEvent.category} />
                        </div>
                        <span className="text-primary-400 text-[10px] font-semibold hover:text-primary-300 transition-colors flex items-center gap-1">
                          View Event <Check size={10} />
                        </span>
                      </div>
                    </div>
                  </div>
                </Link>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
    </aside>
  );
}

import { useState, useRef } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { uploadImage } from '../../utils/upload';

export default function CreatePost({ onSubmit }) {
  const { user } = useAuth();
  const [content, setContent] = useState('');
  const [images, setImages] = useState([]);
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!content.trim() && images.length === 0) return;
    setLoading(true);
    await onSubmit({ content, images, type: 'Discussion' });
    setContent('');
    setImages([]);
    setLoading(false);
  };

  const handleImageChange = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setLoading(true);
    try {
      const url = await uploadImage(file);
      setImages(prev => [...prev, url]);
    } catch (err) {
      alert('Failed to upload image. (Ensure Cloudinary preset is configured)');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-card mb-6 p-4 md:p-6">
      <div className="flex gap-4">
        <img src={user?.avatar || 'https://ui-avatars.com/api/?name=' + (user?.fullName || 'User') + '&background=random'} alt="Avatar" className="w-10 h-10 rounded-full object-cover" />
        <div className="flex-1">
          <form onSubmit={handleSubmit}>
            <textarea
              className="input-field resize-none min-h-[100px] mb-4 bg-dark-900 border-dark-700"
              placeholder="Share a resource, post a doubt, or start a discussion..."
              value={content}
              onChange={(e) => setContent(e.target.value)}
            />
            {images.length > 0 && (
              <div className="flex gap-2 mb-4 overflow-x-auto">
                {images.map((url, idx) => (
                  <div key={idx} className="relative">
                    <img src={url} alt="Uploaded preview" className="h-20 w-20 object-cover rounded-lg border border-dark-700" />
                    <button 
                      type="button" 
                      onClick={() => setImages(images.filter((_, i) => i !== idx))}
                      className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs"
                    >
                      ×
                    </button>
                  </div>
                ))}
              </div>
            )}
            <div className="flex justify-between items-center">
              <div className="flex gap-2">
                <input 
                  type="file" 
                  accept="image/*" 
                  className="hidden" 
                  ref={fileInputRef} 
                  onChange={handleImageChange} 
                />
                <button 
                  type="button" 
                  onClick={() => fileInputRef.current?.click()}
                  className="text-dark-400 hover:text-primary-400 p-2 rounded-lg hover:bg-dark-800 transition-colors flex items-center gap-2"
                >
                  <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                  <span className="text-sm font-medium">Image</span>
                </button>
              </div>
              <button type="submit" disabled={(!content.trim() && images.length === 0) || loading} className="btn-primary w-auto px-6 py-2 text-sm">
                {loading ? 'Posting...' : 'Post'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';

export default function PostCard({ post, onLike }) {
  const [isLiked, setIsLiked] = useState(post.hasLiked);
  const [likesCount, setLikesCount] = useState(post.likesCount);

  const handleLike = async () => {
    const prevLiked = isLiked;
    const prevCount = likesCount;
    setIsLiked(!prevLiked);
    setLikesCount(prevLiked ? prevCount - 1 : prevCount + 1);
    try {
      await onLike(post._id);
    } catch (err) {
      setIsLiked(prevLiked);
      setLikesCount(prevCount);
    }
  };

  const formatDate = (dateString) => {
    const options = { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' };
    return new Date(dateString).toLocaleDateString('en-US', options);
  };

  return (
    <div className="auth-card mb-6 p-4 md:p-6 transition-transform hover:-translate-y-0.5 duration-300">
      <div className="flex justify-between items-start mb-4">
        <div className="flex gap-3 items-center">
          <img 
            src={post.authorId?.avatar || 'https://ui-avatars.com/api/?name=' + (post.authorId?.fullName || 'User') + '&background=random'} 
            alt="Avatar" 
            className="w-11 h-11 rounded-full object-cover border-2 border-dark-800" 
          />
          <div>
            <div className="flex items-center gap-2">
              <h3 className="text-dark-100 font-semibold">{post.authorId?.fullName || 'Unknown User'}</h3>
              {post.authorId?.badges?.length > 0 && (
                <span className="chip text-[10px] px-2 py-0.5 border-primary-500/30">{post.authorId.badges[0]}</span>
              )}
            </div>
            <p className="text-dark-400 text-xs mt-0.5">
              {post.authorId?.role} • {formatDate(post.createdAt)}
            </p>
          </div>
        </div>
        <span className="chip text-[10px] bg-dark-800/80 text-dark-300 border-dark-700">{post.type}</span>
      </div>
      
      <p className="text-dark-200 mb-4 whitespace-pre-wrap text-sm leading-relaxed">{post.content}</p>
      
      {post.images?.length > 0 && (
        <div className={`mb-4 grid gap-2 ${post.images.length > 1 ? 'grid-cols-2' : 'grid-cols-1'}`}>
          {post.images.map((img, idx) => (
            <img key={idx} src={img} alt="Post content" className="w-full rounded-xl object-cover max-h-96 border border-dark-700/50" />
          ))}
        </div>
      )}
      
      {post.tags?.length > 0 && (
        <div className="flex flex-wrap gap-2 mb-4">
          {post.tags.map(tag => (
            <span key={tag} className="text-primary-400 text-xs font-medium">#{tag}</span>
          ))}
        </div>
      )}

      <div className="flex gap-6 mt-4 pt-4 border-t border-dark-800/50">
        <button 
          onClick={handleLike} 
          className={`flex items-center gap-2 text-sm font-medium transition-colors ${isLiked ? 'text-red-400' : 'text-dark-400 hover:text-dark-200'}`}
        >
          <svg className={`w-5 h-5 ${isLiked ? 'fill-current' : 'fill-none stroke-current'}`} viewBox="0 0 24 24" strokeWidth={isLiked ? 0 : 2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
          </svg>
          {likesCount}
        </button>
        <button className="flex items-center gap-2 text-sm font-medium text-dark-400 hover:text-dark-200 transition-colors">
          <svg className="w-5 h-5 fill-none stroke-current" viewBox="0 0 24 24" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
          </svg>
          {post.commentsCount}
        </button>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Home, Calendar, BookOpen, Briefcase, Users, MessageSquare, ShoppingBag, Sparkles, UserPlus, UserCircle, Settings } from 'lucide-react';
import { useAuth } from '../../contexts/AuthContext';

export default function Sidebar() {
  const location = useLocation();
  const { user } = useAuth();
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [theme, setTheme] = useState(localStorage.getItem('theme') || 'dark');

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  const navItems = [
    { name: 'Home', path: '/dashboard', icon: Home },
    { name: 'Events', path: '/events', icon: Calendar },
    { name: 'Resources', path: '/resources', icon: BookOpen },
    { name: 'Opportunities', path: '/opportunities', icon: Briefcase },
    { name: 'Find Teammates', path: '/teammates', icon: UserPlus },
    { name: 'Study Groups', path: '/study-groups', icon: Users },
    { name: 'Messages', path: '/messages', icon: MessageSquare },
    { name: 'Marketplace', path: '/marketplace', icon: ShoppingBag },
    { name: 'AI Solver', path: '/ai-solver', icon: Sparkles },
    { name: 'My Portfolio', path: '/portfolio/me', icon: UserCircle },
  ];

  return (
    <aside className="w-64 fixed left-0 top-0 bottom-0 bg-dark-900 border-r border-dark-800 flex flex-col hidden lg:flex">
      <div className="p-6">
        <h1 className="text-2xl font-bold bg-gradient-to-r from-primary-400 to-primary-300 bg-clip-text text-transparent tracking-tight">
          UniCampus
        </h1>
      </div>

      <nav className="flex-1 px-4 space-y-1 overflow-y-auto">
        {navItems.map((item) => {
          const isActive = location.pathname.startsWith(item.path);
          const Icon = item.icon;
          return (
            <Link
              key={item.name}
              to={item.path}
              className={`flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 group ${
                isActive 
                  ? 'bg-primary-500/10 text-primary-400 font-medium' 
                  : 'text-dark-400 hover:text-dark-100 hover:bg-dark-800'
              }`}
            >
              <Icon size={20} className={isActive ? 'text-primary-400' : 'text-dark-500 group-hover:text-dark-300'} />
              {item.name}
            </Link>
          );
        })}
      </nav>

      <div className="p-4 border-t border-dark-800">
        <Link to="/settings" className="flex items-center gap-3 px-3 py-2.5 rounded-xl text-dark-400 hover:text-dark-100 hover:bg-dark-800 transition-all mb-4">
          <Settings size={20} className="text-dark-500" />
          Settings
        </Link>
        
        <div className="flex items-center gap-3 px-3">
          <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-primary-600 to-primary-400 flex items-center justify-center text-white font-bold shrink-0">
            {user?.fullName?.charAt(0) || 'U'}
          </div>
          <div className="overflow-hidden">
            <p className="text-sm font-medium text-dark-100 truncate">{user?.fullName}</p>
            <p className="text-xs text-dark-500 truncate capitalize">{user?.role}</p>
          </div>
        </div>
      </div>
    </aside>
  );
}

/**
 * @file AuthContext.jsx — Global auth state management
 *
 * ARCHITECTURE:
 *   Firebase is the identity provider. Users SIGN OUT immediately after
 *   registration. Email verification happens externally (user clicks link
 *   in Outlook). The first LOGIN after verification triggers:
 *     reload() → emailVerified check → getIdToken(true) → POST /auth/sync
 *   which creates the MongoDB user record.
 *
 * LIFECYCLE:
 *   Registration: createUser → sendVerification → signOut → /verify-email
 *   Login:        signIn → reload → check emailVerified → getIdToken(true) → /auth/sync
 *   Session:      onAuthStateChanged → reload → getIdToken(true) → /auth/sync
 *
 * NEVER stores tokens in localStorage/sessionStorage.
 * Only registration metadata is stored in sessionStorage temporarily.
 */

import { createContext, useContext, useState, useEffect, useCallback } from 'react';
import {
  onAuthStateChanged,
  signInWithEmailAndPassword,
  createUserWithEmailAndPassword,
  sendEmailVerification,
  sendPasswordResetEmail,
  signOut,
} from 'firebase/auth';
import { auth } from '../config/firebaseClient';
import api from '../config/api';

const AuthContext = createContext(null);

const ALLOWED_DOMAIN = 'adityauniversity.in';

/**
 * Validate email domain before making any Firebase calls.
 */
const validateDomain = (email) => {
  const domain = email.split('@')[1]?.toLowerCase();
  if (domain !== ALLOWED_DOMAIN) {
    throw new Error(`Only @${ALLOWED_DOMAIN} emails are allowed.`);
  }
};

export function AuthProvider({ children }) {
  // ── State ──
  const [user, setUser] = useState(null);                // MongoDB user from backend
  const [loading, setLoading] = useState(true);           // Initial session restoration
  const [authLoading, setAuthLoading] = useState(false);  // Login/register operations

  /**
   * Sync Firebase user with backend MongoDB.
   *
   * PRECONDITIONS (caller must ensure):
   *   - fbUser.emailVerified === true (already checked)
   *   - fbUser.reload() has been called (fresh state)
   *   - fbUser.getIdToken(true) has been called (fresh token)
   */
  const syncWithBackend = useCallback(async (metadata = {}) => {
    try {
      console.debug('[Auth] Calling POST /auth/sync...');
      const { data } = await api.post('/auth/sync', metadata);
      const backendUser = data.data.user;
      setUser(backendUser);
      console.debug('[Auth] Backend sync successful. isNewUser:', data.data.isNewUser);
      return data.data;
    } catch (error) {
      console.error('[Auth] Backend sync failed:', error.response?.data?.message || error.message);
      // If sync fails, sign out to clean state
      await signOut(auth);
      setUser(null);
      throw error;
    }
  }, []);

  /**
   * Core verification + sync sequence.
   * Used by both login() and onAuthStateChanged session restoration.
   *
   * Steps:
   *   1. reload() — get fresh emailVerified from Firebase servers
   *   2. Re-read auth.currentUser (reference may have updated)
   *   3. Check emailVerified — reject if false
   *   4. getIdToken(true) — force a fresh token with updated claims
   *   5. POST /auth/sync — create/fetch MongoDB user
   */
  const verifyAndSync = useCallback(async (fbUser, metadata = {}) => {
    // Step 1: Reload to get fresh state from Firebase servers
    console.debug('[Auth] Reloading Firebase user state...');
    await fbUser.reload();

    // Step 2: Re-read currentUser after reload
    const freshUser = auth.currentUser;
    console.debug('[Auth] After reload — emailVerified:', freshUser?.emailVerified);

    if (!freshUser || !freshUser.emailVerified) {
      console.debug('[Auth] Email not verified. Signing out.');
      await signOut(auth);
      setUser(null);
      throw new Error('Email is not verified. Please check your inbox and verify your email first.');
    }

    // Step 3: Force fresh token with updated email_verified claim
    console.debug('[Auth] Forcing fresh ID token...');
    await freshUser.getIdToken(true);

    // Step 4: Sync with backend
    return await syncWithBackend(metadata);
  }, [syncWithBackend]);

  // ── Firebase session restoration on mount ──
  useEffect(() => {
    console.debug('[Auth] Setting up onAuthStateChanged listener...');

    const unsubscribe = onAuthStateChanged(auth, async (fbUser) => {
      if (fbUser) {
        console.debug('[Auth] Session restore — Firebase user:', fbUser.email);
        try {
          await verifyAndSync(fbUser);
        } catch {
          // verifyAndSync handles cleanup — state is already cleared
        }
      } else {
        console.debug('[Auth] No Firebase session. Clearing state.');
        setUser(null);
      }

      setLoading(false);
    });

    return () => unsubscribe();
  }, [verifyAndSync]);

  /**
   * Register a new user with Firebase email/password.
   *
   * FLOW:
   *   1. Create Firebase user
   *   2. Send verification email with redirect to /login?verified=true
   *   3. Store registration metadata in sessionStorage
   *   4. Sign out immediately (unverified users must NOT stay logged in)
   *   5. Navigate to /verify-email (caller handles this)
   */
  const register = async ({ email, password, fullName, rollNumber, department, yearOfStudy }) => {
    validateDomain(email);
    setAuthLoading(true);

    try {
      const normalizedEmail = email.toLowerCase();
      const credential = await createUserWithEmailAndPassword(auth, normalizedEmail, password);

      // Send verification email with redirect back to login
      const appUrl = import.meta.env.VITE_APP_URL || 'http://localhost:5173';
      await sendEmailVerification(credential.user, {
        url: `${appUrl}/login?verified=true`,
        handleCodeInApp: false,
      });

      // Store registration metadata for first login sync
      sessionStorage.setItem(
        'unicampus_reg_meta',
        JSON.stringify({ fullName, rollNumber, department, yearOfStudy, email: normalizedEmail })
      );

      // Sign out immediately — unverified users must not stay logged in
      // This prevents the "No authenticated user found" issue entirely
      await signOut(auth);

      console.debug('[Auth] Registration complete. User signed out. Verification email sent to:', normalizedEmail);
      return { success: true };
    } finally {
      setAuthLoading(false);
    }
  };

  /**
   * Log in with Firebase email/password.
   *
   * FLOW:
   *   1. signInWithEmailAndPassword
   *   2. reload() + emailVerified check
   *   3. getIdToken(true) for fresh token
   *   4. POST /auth/sync with registration metadata (if first login)
   *   5. Clear sessionStorage metadata
   *   6. Return user data for routing
   */
  const login = async (email, password) => {
    validateDomain(email);
    setAuthLoading(true);

    try {
      const normalizedEmail = email.toLowerCase();
      console.debug('[Auth] Logging in:', normalizedEmail);

      const credential = await signInWithEmailAndPassword(auth, normalizedEmail, password);

      // Read registration metadata (only exists for first login after verification)
      const metaRaw = sessionStorage.getItem('unicampus_reg_meta');
      const metadata = metaRaw ? JSON.parse(metaRaw) : {};

      // verifyAndSync does: reload → emailVerified check → getIdToken(true) → /auth/sync
      const result = await verifyAndSync(credential.user, metadata);

      // Clear temporary metadata after successful sync
      sessionStorage.removeItem('unicampus_reg_meta');

      console.debug('[Auth] Login + sync successful:', normalizedEmail);
      return result;
    } finally {
      setAuthLoading(false);
    }
  };

  /**
   * Send password reset email.
   */
  const resetPassword = async (email) => {
    validateDomain(email);
    await sendPasswordResetEmail(auth, email.toLowerCase());
  };

  /**
   * Change password (requires re-authentication).
   */
  const changePassword = async (oldPassword, newPassword) => {
    setAuthLoading(true);
    try {
      if (!auth.currentUser) throw new Error('No authenticated user');
      
      const { EmailAuthProvider, reauthenticateWithCredential, updatePassword } = await import('firebase/auth');
      const credential = EmailAuthProvider.credential(auth.currentUser.email, oldPassword);
      
      await reauthenticateWithCredential(auth.currentUser, credential);
      await updatePassword(auth.currentUser, newPassword);
      console.debug('[Auth] Password changed successfully.');
    } finally {
      setAuthLoading(false);
    }
  };

  /**
   * Sign out from both Firebase and app state.
   */
  const logout = async () => {
    await signOut(auth);
    setUser(null);
    console.debug('[Auth] Logged out. State cleared.');
  };

  const value = {
    // State
    user,
    setUser,
    loading,
    authLoading,

    // Auth methods
    register,
    login,
    logout,
    resetPassword,
    changePassword,

    // Computed
    isAuthenticated: !!user,
    needsOnboarding: user && !user.onboardingCompleted && !user.onboardingSkipped,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

/**
 * Hook to access auth context.
 */
export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import api from '../config/api';

export default function OnboardingPage() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const [form, setForm] = useState({
    bio: '',
    skills: '',
    interests: '',
    techStack: '',
    rolesPreferred: '',
    availability: '',
    github: '',
    portfolio: '',
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleChange = (e) => {
    setForm((prev) => ({ ...prev, [e.target.name]: e.target.value }));
    setError('');
  };

  /**
   * Parse comma-separated string into trimmed array.
   */
  const toArray = (str) =>
    str ? str.split(',').map((s) => s.trim()).filter(Boolean) : [];

  const handleComplete = async () => {
    setLoading(true);
    setError('');

    try {
      await api.post('/users/onboarding', {
        bio: form.bio.trim(),
        skills: toArray(form.skills),
        interests: toArray(form.interests),
        techStack: toArray(form.techStack),
        rolesPreferred: toArray(form.rolesPreferred),
        availability: form.availability || undefined,
        github: form.github.trim() || undefined,
        portfolio: form.portfolio.trim() || undefined,
      });

      // Force page reload to refresh auth state from backend
      window.location.href = '/dashboard';
    } catch (err) {
      setError(err.response?.data?.message || err.message || 'Failed to save. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleSkip = async () => {
    setLoading(true);
    try {
      await api.post('/users/onboarding/skip');
      window.location.href = '/dashboard';
    } catch (err) {
      setError(err.response?.data?.message || err.message || 'Failed to skip.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-dark-950 relative overflow-hidden">
      {/* Background */}
      <div className="absolute top-0 left-1/3 w-[500px] h-[500px] bg-primary-600/5 rounded-full blur-3xl" />
      <div className="absolute bottom-0 right-1/3 w-[400px] h-[400px] bg-primary-400/5 rounded-full blur-3xl" />

      <div className="relative z-10 max-w-2xl mx-auto px-4 py-12">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold bg-gradient-to-r from-primary-400 to-primary-300 bg-clip-text text-transparent">
            Welcome to UniCampus
          </h1>
          <p className="text-dark-400 mt-2">
            Hey {user?.fullName || 'there'}! Tell us about yourself.
          </p>
          <p className="text-dark-500 text-sm mt-1">All fields are optional — you can update later.</p>
        </div>

        {/* Form Card */}
        <div className="auth-card space-y-5" id="onboarding-form">
          {error && (
            <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-sm">
              {error}
            </div>
          )}

          {/* Bio */}
          <div>
            <label htmlFor="onb-bio" className="label-text">Bio</label>
            <textarea
              id="onb-bio"
              name="bio"
              value={form.bio}
              onChange={handleChange}
              placeholder="A short bio about yourself..."
              className="input-field resize-none h-24"
              maxLength={500}
            />
            <p className="text-dark-600 text-xs mt-1">{form.bio.length}/500</p>
          </div>

          {/* Skills & Interests */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label htmlFor="onb-skills" className="label-text">Skills</label>
              <input
                id="onb-skills"
                name="skills"
                value={form.skills}
                onChange={handleChange}
                placeholder="react, python, figma"
                className="input-field"
              />
              <p className="text-dark-600 text-xs mt-1">Comma-separated</p>
            </div>
            <div>
              <label htmlFor="onb-interests" className="label-text">Interests</label>
              <input
                id="onb-interests"
                name="interests"
                value={form.interests}
                onChange={handleChange}
                placeholder="web dev, AI, design"
                className="input-field"
              />
              <p className="text-dark-600 text-xs mt-1">Comma-separated</p>
            </div>
          </div>

          {/* Tech Stack & Preferred Roles */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label htmlFor="onb-techStack" className="label-text">Tech Stack</label>
              <input
                id="onb-techStack"
                name="techStack"
                value={form.techStack}
                onChange={handleChange}
                placeholder="MERN, Flutter, Django"
                className="input-field"
              />
              <p className="text-dark-600 text-xs mt-1">Comma-separated</p>
            </div>
            <div>
              <label htmlFor="onb-roles" className="label-text">Preferred Roles</label>
              <input
                id="onb-roles"
                name="rolesPreferred"
                value={form.rolesPreferred}
                onChange={handleChange}
                placeholder="frontend, backend, PM"
                className="input-field"
              />
              <p className="text-dark-600 text-xs mt-1">Comma-separated</p>
            </div>
          </div>

          {/* Availability */}
          <div>
            <label htmlFor="onb-availability" className="label-text">Availability</label>
            <select
              id="onb-availability"
              name="availability"
              value={form.availability}
              onChange={handleChange}
              className="input-field"
            >
              <option value="">Select...</option>
              <option value="available">Available</option>
              <option value="busy">Busy</option>
              <option value="looking-for-team">Looking for Team</option>
              <option value="not-available">Not Available</option>
            </select>
          </div>

          {/* Social Links */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label htmlFor="onb-github" className="label-text">GitHub</label>
              <input
                id="onb-github"
                name="github"
                value={form.github}
                onChange={handleChange}
                placeholder="https://github.com/username"
                className="input-field"
              />
            </div>
            <div>
              <label htmlFor="onb-portfolio" className="label-text">Portfolio</label>
              <input
                id="onb-portfolio"
                name="portfolio"
                value={form.portfolio}
                onChange={handleChange}
                placeholder="https://yourportfolio.dev"
                className="input-field"
              />
            </div>
          </div>

          {/* Actions */}
          <div className="flex flex-col gap-3 pt-2">
            <button
              onClick={handleComplete}
              className="btn-primary"
              disabled={loading}
              id="complete-onboarding-btn"
            >
              {loading ? 'Saving...' : 'Complete Setup'}
            </button>
            <button
              onClick={handleSkip}
              className="btn-secondary"
              disabled={loading}
              id="skip-onboarding-btn"
            >
              Skip for now
            </button>
          </div>
        </div>

        {/* Footer */}
        <p className="text-center text-dark-600 text-xs mt-6">
          You can always update your profile from settings.
        </p>
      </div>
    </div>
  );
}

import { useEffect, useRef, useState } from 'react';
import DashboardLayout from '../../components/layout/DashboardLayout';
import { useAIChat } from '../../hooks/useAIChat';
import { useAuth } from '../../contexts/AuthContext';
import {
  Send,
  Plus,
  MessageSquare,
  Trash2,
  Bot,
  User,
  Sparkles,
  Clock,
  ChevronLeft,
  Loader2,
  AlertCircle,
  Zap,
  BookOpen,
  Code2,
  GraduationCap,
} from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';

// ─── Lightweight Markdown Renderer ───
function MarkdownContent({ content }) {
  const renderMarkdown = (text) => {
    const parts = [];
    let remaining = text;
    let key = 0;

    // Split by code blocks first
    const codeBlockRegex = /```(\w*)\n?([\s\S]*?)```/g;
    let lastIndex = 0;
    let match;

    while ((match = codeBlockRegex.exec(remaining)) !== null) {
      // Text before code block
      if (match.index > lastIndex) {
        parts.push(
          <span key={key++}>{renderInlineMarkdown(remaining.slice(lastIndex, match.index))}</span>
        );
      }

      // Code block
      const language = match[1] || 'code';
      const code = match[2].trim();
      parts.push(
        <div key={key++} className="my-4 rounded-xl overflow-hidden border border-dark-700/50 shadow-lg">
          <div className="flex items-center justify-between px-4 py-2 bg-dark-800 border-b border-dark-700/50">
            <span className="text-[10px] font-bold text-primary-400 uppercase tracking-widest">{language}</span>
            <button
              onClick={() => navigator.clipboard.writeText(code)}
              className="text-[10px] font-bold text-dark-500 hover:text-primary-400 uppercase tracking-widest transition-colors"
            >
              Copy
            </button>
          </div>
          <pre className="p-4 bg-dark-950 overflow-x-auto text-sm leading-relaxed">
            <code className="text-dark-200 font-mono">{code}</code>
          </pre>
        </div>
      );

      lastIndex = match.index + match[0].length;
    }

    // Remaining text after last code block
    if (lastIndex < remaining.length) {
      parts.push(
        <span key={key++}>{renderInlineMarkdown(remaining.slice(lastIndex))}</span>
      );
    }

    return parts.length > 0 ? parts : renderInlineMarkdown(text);
  };

  const renderInlineMarkdown = (text) => {
    return text.split('\n').map((line, i) => {
      // Headers
      if (line.startsWith('### ')) return <h4 key={i} className="text-dark-100 font-bold text-base mt-4 mb-2">{processInline(line.slice(4))}</h4>;
      if (line.startsWith('## ')) return <h3 key={i} className="text-dark-100 font-bold text-lg mt-4 mb-2">{processInline(line.slice(3))}</h3>;
      if (line.startsWith('# ')) return <h2 key={i} className="text-dark-100 font-bold text-xl mt-4 mb-2">{processInline(line.slice(2))}</h2>;

      // Bullet points
      if (line.startsWith('- ') || line.startsWith('* ')) {
        return (
          <div key={i} className="flex gap-2 my-1">
            <span className="text-primary-500 mt-1.5 text-xs">●</span>
            <span>{processInline(line.slice(2))}</span>
          </div>
        );
      }

      // Numbered lists
      const numMatch = line.match(/^(\d+)\.\s/);
      if (numMatch) {
        return (
          <div key={i} className="flex gap-2 my-1">
            <span className="text-primary-400 font-bold text-xs mt-0.5 min-w-[1.2em]">{numMatch[1]}.</span>
            <span>{processInline(line.slice(numMatch[0].length))}</span>
          </div>
        );
      }

      // Empty line → spacer
      if (line.trim() === '') return <div key={i} className="h-2" />;

      // Regular paragraph
      return <p key={i} className="my-1">{processInline(line)}</p>;
    });
  };

  const processInline = (text) => {
    // Process inline code, bold, italic
    const parts = [];
    let remaining = text;
    let key = 0;

    // Inline code: `code`
    const inlineCodeRegex = /`([^`]+)`/g;
    let lastIdx = 0;
    let m;

    while ((m = inlineCodeRegex.exec(remaining)) !== null) {
      if (m.index > lastIdx) {
        parts.push(<span key={key++}>{processBoldItalic(remaining.slice(lastIdx, m.index))}</span>);
      }
      parts.push(
        <code key={key++} className="px-1.5 py-0.5 bg-dark-800 border border-dark-700/50 rounded-md text-primary-300 text-[13px] font-mono">
          {m[1]}
        </code>
      );
      lastIdx = m.index + m[0].length;
    }

    if (lastIdx < remaining.length) {
      parts.push(<span key={key++}>{processBoldItalic(remaining.slice(lastIdx))}</span>);
    }

    return parts.length > 0 ? parts : processBoldItalic(text);
  };

  const processBoldItalic = (text) => {
    // **bold**
    return text.split(/\*\*(.+?)\*\*/g).map((part, i) =>
      i % 2 === 1 ? <strong key={i} className="text-dark-100 font-bold">{part}</strong> : part
    );
  };

  return <div className="text-[15px] leading-relaxed">{renderMarkdown(content)}</div>;
}


// ─── Main Page ───
export default function AIDoubtSolverPage() {
  const { user } = useAuth();
  const {
    conversations,
    messages,
    activeConversation,
    loading,
    sending,
    fetchConversations,
    loadConversation,
    sendMessage,
    deleteConversation,
    startNewChat,
  } = useAIChat();

  const [input, setInput] = useState('');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const messagesEndRef = useRef(null);
  const textareaRef = useRef(null);

  useEffect(() => {
    fetchConversations();
  }, [fetchConversations]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, sending]);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = Math.min(textareaRef.current.scrollHeight, 160) + 'px';
    }
  }, [input]);

  const handleSend = async () => {
    const trimmed = input.trim();
    if (!trimmed || sending) return;

    const currentInput = trimmed;
    setInput('');

    try {
      await sendMessage(currentInput, activeConversation?._id || null);
    } catch {
      // Error is handled in the hook
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleSelectConversation = (conv) => {
    loadConversation(conv._id);
    // On mobile, close sidebar after selection
    if (window.innerWidth < 1024) setSidebarOpen(false);
  };

  const handleNewChat = () => {
    startNewChat();
    if (window.innerWidth < 1024) setSidebarOpen(false);
  };

  const handleDeleteConversation = (e, id) => {
    e.stopPropagation();
    if (window.confirm('Delete this conversation?')) {
      deleteConversation(id);
    }
  };

  // ─── Quick Action Suggestions ───
  const suggestions = [
    { icon: BookOpen, text: 'Explain DBMS normalization', color: 'text-blue-400' },
    { icon: Code2, text: 'Help me debug this code', color: 'text-green-400' },
    { icon: GraduationCap, text: 'Give DSA roadmap', color: 'text-purple-400' },
    { icon: Zap, text: 'Placement preparation tips', color: 'text-amber-400' },
  ];

  return (
    <DashboardLayout hideWidgets>
      <div className="flex h-[calc(100vh-7rem)] -mx-4 lg:-mx-8 -mt-4 lg:-mt-8 overflow-hidden">

        {/* ── Conversation Sidebar ── */}
        <div className={`${sidebarOpen ? 'w-80 border-r border-dark-800' : 'w-0'} transition-all duration-300 bg-dark-900/50 backdrop-blur-xl flex-shrink-0 flex flex-col overflow-hidden`}>

          {/* Sidebar Header */}
          <div className="p-4 border-b border-dark-800/50 flex-shrink-0">
            <button
              onClick={handleNewChat}
              className="w-full btn-primary py-3 flex items-center justify-center gap-2 shadow-lg shadow-primary-500/15 text-sm"
            >
              <Plus size={18} strokeWidth={2.5} />
              New Doubt
            </button>
          </div>

          {/* Conversation List */}
          <div className="flex-1 overflow-y-auto hide-scrollbar p-3 space-y-1">
            {conversations.length === 0 ? (
              <div className="text-center py-12">
                <MessageSquare size={32} className="mx-auto text-dark-600 mb-3" />
                <p className="text-dark-500 text-xs font-bold uppercase tracking-widest">No conversations yet</p>
              </div>
            ) : (
              conversations.map(conv => (
                <button
                  key={conv._id}
                  onClick={() => handleSelectConversation(conv)}
                  className={`w-full text-left px-4 py-3 rounded-xl transition-all duration-200 group flex items-center justify-between gap-2 ${
                    activeConversation?._id === conv._id
                      ? 'bg-primary-500/10 border border-primary-500/20 text-primary-300'
                      : 'hover:bg-dark-800/80 text-dark-300 border border-transparent'
                  }`}
                >
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold truncate">{conv.title}</p>
                    <p className="text-[10px] text-dark-500 mt-0.5 flex items-center gap-1">
                      <Clock size={10} />
                      {formatDistanceToNow(new Date(conv.updatedAt), { addSuffix: true })}
                    </p>
                  </div>
                  <button
                    onClick={(e) => handleDeleteConversation(e, conv._id)}
                    className="opacity-0 group-hover:opacity-100 p-1.5 rounded-lg hover:bg-red-500/10 text-dark-500 hover:text-red-400 transition-all"
                  >
                    <Trash2 size={14} />
                  </button>
                </button>
              ))
            )}
          </div>
        </div>

        {/* ── Main Chat Area ── */}
        <div className="flex-1 flex flex-col min-w-0">

          {/* Chat Header */}
          <div className="h-14 border-b border-dark-800/50 bg-dark-900/30 backdrop-blur-xl flex items-center px-4 gap-3 flex-shrink-0">
            <button
              onClick={() => setSidebarOpen(!sidebarOpen)}
              className="p-2 rounded-xl hover:bg-dark-800 text-dark-400 hover:text-dark-200 transition-colors"
            >
              {sidebarOpen ? <ChevronLeft size={20} /> : <MessageSquare size={20} />}
            </button>
            <div className="flex items-center gap-2.5">
              <div className="w-8 h-8 bg-gradient-to-br from-primary-500 to-primary-600 rounded-xl flex items-center justify-center shadow-md shadow-primary-500/20">
                <Sparkles size={16} className="text-white" />
              </div>
              <div>
                <h2 className="text-sm font-bold text-dark-100">
                  {activeConversation ? activeConversation.title : 'AI Doubt Solver'}
                </h2>
                <p className="text-[10px] text-dark-500 font-medium">
                  {sending ? 'Thinking...' : 'Powered by UniBot'}
                </p>
              </div>
            </div>
          </div>

          {/* Messages Area */}
          <div className="flex-1 overflow-y-auto hide-scrollbar">
            {messages.length === 0 && !activeConversation ? (
              /* ── Empty State / Welcome ── */
              <div className="h-full flex flex-col items-center justify-center p-8 text-center">
                <div className="w-20 h-20 bg-gradient-to-br from-primary-500/20 to-primary-600/10 rounded-3xl flex items-center justify-center mb-6 border border-primary-500/20 shadow-xl shadow-primary-500/5">
                  <Bot size={40} className="text-primary-400" />
                </div>
                <h2 className="text-2xl font-black text-dark-100 mb-2">
                  Hey{user?.fullName ? `, ${user.fullName.split(' ')[0]}` : ''}! 👋
                </h2>
                <p className="text-dark-400 max-w-md mb-10 font-medium leading-relaxed">
                  I'm <span className="text-primary-400 font-bold">UniBot</span>, your AI academic assistant.
                  Ask me any doubt — from DBMS to DSA, coding bugs to placement prep.
                </p>

                {/* Quick Action Suggestions */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 max-w-lg w-full">
                  {suggestions.map((s, i) => (
                    <button
                      key={i}
                      onClick={() => { setInput(s.text); textareaRef.current?.focus(); }}
                      className="auth-card p-4 text-left hover:border-primary-500/30 transition-all duration-200 group cursor-pointer border-dark-800"
                    >
                      <s.icon size={18} className={`${s.color} mb-2 group-hover:scale-110 transition-transform`} />
                      <p className="text-dark-200 text-sm font-semibold group-hover:text-primary-300 transition-colors">
                        {s.text}
                      </p>
                    </button>
                  ))}
                </div>
              </div>
            ) : (
              /* ── Chat Messages ── */
              <div className="max-w-4xl mx-auto p-4 lg:p-6 space-y-6">
                {messages.map((msg, index) => (
                  <div key={index} className={`flex gap-3 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    {msg.role === 'assistant' && (
                      <div className="flex-shrink-0 w-8 h-8 bg-gradient-to-br from-primary-500 to-primary-600 rounded-xl flex items-center justify-center mt-1 shadow-md shadow-primary-500/20">
                        <Bot size={16} className="text-white" />
                      </div>
                    )}
                    <div className={`max-w-[85%] lg:max-w-[75%] ${
                      msg.role === 'user'
                        ? 'bg-primary-600 text-white rounded-2xl rounded-br-none px-5 py-3 shadow-lg shadow-primary-600/10'
                        : 'bg-dark-800/60 text-dark-200 rounded-2xl rounded-bl-none px-5 py-4 border border-dark-700/30 shadow-lg shadow-black/10'
                    }`}>
                      {msg.role === 'assistant' ? (
                        <MarkdownContent content={msg.content} />
                      ) : (
                        <p className="text-[15px] leading-relaxed whitespace-pre-wrap font-medium">{msg.content}</p>
                      )}
                    </div>
                    {msg.role === 'user' && (
                      <div className="flex-shrink-0 w-8 h-8 bg-dark-800 rounded-xl flex items-center justify-center mt-1 border border-dark-700/50">
                        <User size={16} className="text-dark-400" />
                      </div>
                    )}
                  </div>
                ))}

                {/* Thinking indicator */}
                {sending && (
                  <div className="flex gap-3 items-start">
                    <div className="flex-shrink-0 w-8 h-8 bg-gradient-to-br from-primary-500 to-primary-600 rounded-xl flex items-center justify-center shadow-md shadow-primary-500/20">
                      <Bot size={16} className="text-white" />
                    </div>
                    <div className="bg-dark-800/60 rounded-2xl rounded-bl-none px-5 py-4 border border-dark-700/30">
                      <div className="flex items-center gap-3">
                        <Loader2 size={16} className="text-primary-400 animate-spin" />
                        <span className="text-dark-400 text-sm font-medium animate-pulse">UniBot is thinking...</span>
                      </div>
                    </div>
                  </div>
                )}

                <div ref={messagesEndRef} />
              </div>
            )}
          </div>

          {/* ── Input Area ── */}
          <div className="border-t border-dark-800/50 p-4 bg-dark-900/30 backdrop-blur-xl flex-shrink-0">
            <div className="max-w-4xl mx-auto">
              <div className="flex gap-3 bg-dark-800/40 p-2 rounded-2xl border border-dark-700/30 focus-within:border-primary-500/40 transition-all shadow-inner">
                <textarea
                  ref={textareaRef}
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={handleKeyDown}
                  placeholder="Ask your doubt..."
                  rows={1}
                  className="flex-1 bg-transparent border-none text-dark-100 px-4 py-2.5 focus:ring-0 text-sm font-medium resize-none hide-scrollbar placeholder-dark-500"
                  style={{ maxHeight: '160px' }}
                  disabled={sending}
                />
                <button
                  onClick={handleSend}
                  disabled={!input.trim() || sending}
                  className="self-end p-3 bg-primary-600 text-white rounded-xl shadow-lg shadow-primary-600/20 hover:bg-primary-500 disabled:opacity-40 disabled:bg-dark-700 disabled:shadow-none transition-all"
                >
                  {sending ? <Loader2 size={18} className="animate-spin" /> : <Send size={18} strokeWidth={2.5} />}
                </button>
              </div>
              <p className="text-[10px] text-dark-600 text-center mt-2 font-medium">
                UniBot may make mistakes. Verify important information.
              </p>
            </div>
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
}

import { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { 
  ArrowLeft, 
  IndianRupee, 
  Tag, 
  Info, 
  Phone, 
  Clock, 
  Trash2, 
  CheckCircle2, 
  AlertCircle,
  ExternalLink
} from 'lucide-react';
import DashboardLayout from '../../components/layout/DashboardLayout';
import { useMarketplace } from '../../hooks/useMarketplace';
import { useAuth } from '../../contexts/AuthContext';
import { format } from 'date-fns';

export default function ItemDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const { getItem, deleteListing, toggleSoldStatus, loading } = useMarketplace();
  const [item, setItem] = useState(null);
  const [isDeleting, setIsDeleting] = useState(false);

  useEffect(() => {
    const fetchItem = async () => {
      try {
        const data = await getItem(id);
        setItem(data);
      } catch (err) {
        console.error(err);
      }
    };
    fetchItem();
  }, [id]);

  const handleDelete = async () => {
    if (!window.confirm('Are you sure you want to remove this listing?')) return;
    
    setIsDeleting(true);
    try {
      await deleteListing(id);
      navigate('/marketplace');
    } catch (err) {
      alert(err.message);
    } finally {
      setIsDeleting(false);
    }
  };

  const handleToggleSold = async () => {
    try {
      const updatedItem = await toggleSoldStatus(id);
      setItem(updatedItem);
    } catch (err) {
      alert(err.message);
    }
  };

  if (loading && !item) {
    return (
      <DashboardLayout>
        <div className="flex flex-col items-center justify-center py-32 gap-4">
          <div className="w-12 h-12 border-4 border-dark-800 border-t-primary-500 rounded-full animate-spin"></div>
          <p className="text-dark-400 font-bold tracking-widest uppercase text-xs">Loading Details...</p>
        </div>
      </DashboardLayout>
    );
  }

  if (!item) return null;

  const isOwner = user?.id === item.sellerId?._id;

  return (
    <DashboardLayout>
      <div className="max-w-6xl mx-auto">
        {/* Back Button */}
        <Link 
          to="/marketplace" 
          className="inline-flex items-center gap-2 text-dark-400 hover:text-primary-400 transition-colors mb-8 group font-semibold"
        >
          <div className="p-2 bg-dark-900 rounded-xl group-hover:bg-primary-500/10 transition-colors border border-dark-800">
            <ArrowLeft size={20} />
          </div>
          Back to Marketplace
        </Link>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
          {/* Left Column: Image */}
          <div className="lg:col-span-7">
            <div className="auth-card p-0 overflow-hidden rounded-3xl border-dark-800 shadow-2xl relative">
              <img 
                src={item.image} 
                className="w-full aspect-[4/3] object-cover" 
                alt={item.title} 
              />
              {item.isSold && (
                <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center">
                  <div className="bg-red-500 text-white text-xl font-black px-8 py-4 rounded-3xl shadow-2xl uppercase tracking-[0.2em] -rotate-12 border-4 border-white/20">
                    Sold Out
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Right Column: Details */}
          <div className="lg:col-span-5 space-y-8">
            <div className="auth-card p-8 border-dark-800 shadow-xl relative overflow-hidden">
              {/* Background Glow */}
              <div className="absolute top-0 right-0 w-32 h-32 bg-primary-500/5 blur-3xl rounded-full"></div>
              
              <div className="relative z-10">
                <div className="flex items-center justify-between mb-4">
                  <span className="bg-primary-500/10 text-primary-400 text-[10px] font-black px-3 py-1.5 rounded-xl border border-primary-500/20 uppercase tracking-widest">
                    {item.category}
                  </span>
                  <div className="flex items-center gap-1.5 text-dark-500 text-xs font-bold uppercase tracking-tighter">
                    <Clock size={12} />
                    {format(new Date(item.createdAt), 'MMM dd, yyyy')}
                  </div>
                </div>

                <h1 className="text-3xl font-black text-dark-100 leading-tight mb-2">
                  {item.title}
                </h1>
                
                <div className="flex items-center gap-3 mb-8">
                  <div className="text-4xl font-black text-primary-400 flex items-center">
                    <IndianRupee size={28} strokeWidth={3} />
                    {item.price.toLocaleString('en-IN')}
                  </div>
                  <div className="h-6 w-[1px] bg-dark-800 mx-2"></div>
                  <div className={`text-sm font-bold px-3 py-1 rounded-lg border ${
                    item.condition === 'New' ? 'text-green-400 border-green-500/20 bg-green-500/5' :
                    item.condition === 'Like New' ? 'text-blue-400 border-blue-500/20 bg-blue-500/5' :
                    'text-orange-400 border-orange-500/20 bg-orange-500/5'
                  }`}>
                    {item.condition}
                  </div>
                </div>

                <div className="space-y-6">
                  <div>
                    <h3 className="text-xs font-black text-dark-500 uppercase tracking-[0.2em] mb-3 flex items-center gap-2">
                      <Info size={14} /> Item Description
                    </h3>
                    <p className="text-dark-300 text-base leading-relaxed whitespace-pre-wrap font-medium">
                      {item.description}
                    </p>
                  </div>

                  <div className="pt-6 border-t border-dark-800/50">
                    <h3 className="text-xs font-black text-dark-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                      <Phone size={14} /> Seller Information
                    </h3>
                    
                    <div className="flex items-center gap-4 mb-6">
                      <img 
                        src={item.sellerId?.avatar || `https://ui-avatars.com/api/?name=${item.sellerId?.fullName}&background=random`} 
                        className="w-14 h-14 rounded-2xl object-cover border-2 border-dark-800"
                        alt="Seller"
                      />
                      <div>
                        <p className="text-dark-100 font-black text-lg">{item.sellerId?.fullName}</p>
                        <p className="text-dark-500 text-sm font-bold flex items-center gap-2 uppercase tracking-tighter">
                          {item.sellerId?.rollNumber} • <span className="text-primary-500/80">{item.sellerId?.role}</span>
                        </p>
                      </div>
                    </div>

                    {isOwner ? (
                      <div className="grid grid-cols-2 gap-4 mt-8">
                        <button 
                          onClick={handleToggleSold}
                          className={`flex items-center justify-center gap-2 py-4 rounded-2xl font-black text-sm uppercase tracking-widest transition-all ${
                            item.isSold 
                            ? 'bg-green-500/10 text-green-400 border border-green-500/20 hover:bg-green-500/20' 
                            : 'bg-dark-800 text-dark-200 border border-dark-700 hover:bg-dark-700'
                          }`}
                        >
                          {item.isSold ? <CheckCircle2 size={18} /> : <Tag size={18} />}
                          {item.isSold ? 'Mark Available' : 'Mark Sold'}
                        </button>
                        <button 
                          onClick={handleDelete}
                          disabled={isDeleting}
                          className="flex items-center justify-center gap-2 py-4 bg-red-500/10 text-red-400 border border-red-500/20 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-red-500 hover:text-white transition-all disabled:opacity-50"
                        >
                          <Trash2 size={18} />
                          {isDeleting ? 'Deleting...' : 'Remove'}
                        </button>
                      </div>
                    ) : (
                      <div className="mt-8 space-y-4">
                        <div className="bg-dark-900/80 rounded-2xl p-5 border border-dark-800 shadow-inner">
                          <p className="text-xs text-dark-500 font-bold uppercase tracking-[0.15em] mb-1">Contact Seller via:</p>
                          <p className="text-primary-400 font-black text-xl break-words">
                            {item.contactInfo}
                          </p>
                        </div>
                        
                        <a 
                          href={`tel:${item.contactInfo}`}
                          className="btn-primary w-full py-5 rounded-2xl font-black text-sm uppercase tracking-[0.2em] shadow-2xl shadow-primary-500/20 flex items-center justify-center gap-3 group"
                        >
                          <Phone size={18} strokeWidth={3} className="group-hover:rotate-12 transition-transform" />
                          Contact Seller Now
                        </a>
                        
                        <p className="text-[10px] text-dark-500 text-center font-bold uppercase tracking-widest flex items-center justify-center gap-2">
                          <AlertCircle size={10} /> Transactions happen outside this app
                        </p>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
}

